import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Bar, Doughnut } from 'react-chartjs-2';
import 'chart.js/auto';
import api from './api';
import { complaintTypes, priorityOptions, statusLabels, statusOptions } from './constants';

const chartColors = ['#0b6f5f', '#1f7a8c', '#4c956c', '#d08c31', '#8a4f7d', '#5d6d7e', '#c44536'];

function normalizeText(value) {
  return String(value || '').toLowerCase();
}

function groupCount(items, key) {
  const map = new Map();

  items.forEach((item) => {
    const value = key(item) || 'Nao informado';
    map.set(value, (map.get(value) || 0) + 1);
  });

  return Array.from(map.entries())
    .map(([label, total]) => ({ label, total }))
    .sort((a, b) => b.total - a.total);
}

function buildBarData(rows) {
  return {
    labels: rows.map((row) => row.label),
    datasets: [{
      label: 'Reclamacoes',
      data: rows.map((row) => row.total),
      backgroundColor: '#0b6f5f',
      borderRadius: 6
    }]
  };
}

function buildDoughnutData(rows) {
  return {
    labels: rows.map((row) => row.label),
    datasets: [{
      data: rows.map((row) => row.total),
      backgroundColor: rows.map((_, index) => chartColors[index % chartColors.length]),
      borderWidth: 0
    }]
  };
}

function formatProtocol(item) {
  if (item.protocol) return item.protocol;
  const year = item.created_at ? new Date(item.created_at).getFullYear() : new Date().getFullYear();
  return `GRC-${year}-${String(item.id).padStart(6, '0')}`;
}

function formatShortDate(value) {
  if (!value) return 'Sem prazo';
  return new Intl.DateTimeFormat('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  }).format(new Date(value));
}

function priorityLabel(value) {
  return priorityOptions.find((option) => option.value === value)?.label || 'Media';
}

function daysSince(value) {
  if (!value) return 0;
  const date = new Date(value);

  if (Number.isNaN(date.getTime())) return 0;

  return Math.max(0, Math.floor((Date.now() - date.getTime()) / (1000 * 60 * 60 * 24)));
}

function buildDeadlineInfo(item) {
  if (item.status === 'resolvida') {
    return {
      state: 'closed',
      label: 'Fechada',
      detail: item.closed_at ? formatShortDate(item.closed_at) : 'Sem data'
    };
  }

  const dueAt = item.due_at ? new Date(item.due_at) : null;

  if (!dueAt || Number.isNaN(dueAt.getTime())) {
    return {
      state: 'neutral',
      label: 'Sem SLA',
      detail: 'Sem prazo'
    };
  }

  const diffMs = dueAt.getTime() - Date.now();
  const hours = Math.ceil(Math.abs(diffMs) / (1000 * 60 * 60));

  if (diffMs < 0) {
    return {
      state: 'overdue',
      label: 'Vencida',
      detail: `${hours}h em atraso`
    };
  }

  if (diffMs <= 12 * 60 * 60 * 1000) {
    return {
      state: 'warning',
      label: 'Perto de vencer',
      detail: `Restam ${Math.max(hours, 1)}h`
    };
  }

  return {
    state: 'ontime',
    label: 'No prazo',
    detail: `Vence ${formatShortDate(item.due_at)}`
  };
}

function buildOperationalStage(item) {
  if (item.status === 'resolvida') {
    return {
      owner: 'protocolo encerrado',
      label: 'Fechada pelo SAC',
      since: item.closed_at || item.updated_at || item.created_at
    };
  }

  if (!item.treatment_at) {
    return {
      owner: 'coordenador, gerente ou Supervisor CRC',
      label: 'Aguardando tratativa da gestao',
      since: item.created_at
    };
  }

  if (item.priority === 'alta' && !item.supervisor_approval_at) {
    return {
      owner: 'Supervisor do CRC',
      label: 'Aguardando aceite de prioridade alta',
      since: item.treatment_at
    };
  }

  if (!item.patient_contacted_at) {
    return {
      owner: 'Operador de SAC',
      label: 'Aguardando contato com paciente',
      since: item.supervisor_approval_at || item.treatment_at
    };
  }

  return {
    owner: 'Operador de SAC',
    label: 'Aguardando fechamento do protocolo',
    since: item.patient_contacted_at
  };
}

const chartOptions = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: {
      position: 'bottom'
    }
  }
};

function ComplaintListItem({ item, onOpen }) {
  const deadline = buildDeadlineInfo(item);
  const stage = buildOperationalStage(item);
  const stoppedDays = daysSince(stage.since);

  return (
    <button
      type="button"
      className={`complaint-list-item deadline-${deadline.state}`}
      onClick={onOpen}
    >
      <div className="complaint-list-main">
        <div className="complaint-list-title">
          <span className={`status-pill ${item.status || 'aberta'}`}>
            {statusLabels[item.status] || 'Aberta'}
          </span>
          <strong>{formatProtocol(item)}</strong>
        </div>
        <div>
          <h3>{item.patient_name || 'Paciente nao informado'}</h3>
          <p>{item.clinic_name || 'Clinica nao informada'} · {item.city || 'Cidade'} / {item.state || 'UF'}</p>
        </div>
      </div>

      <div className="complaint-list-meta">
        <span>{item.complaint_type || 'Tipo nao informado'}</span>
        <span>{item.channel || 'Canal nao informado'}</span>
        <span>Prioridade {priorityLabel(item.priority)}</span>
        <span>{item.region || 'Regiao nao informada'}</span>
      </div>

      <div className="operational-flow">
        <span className={`deadline-chip ${deadline.state}`}>
          {deadline.label} · {deadline.detail}
        </span>
        <span className="stage-chip">
          Parada com {stage.owner} ha {stoppedDays} {stoppedDays === 1 ? 'dia' : 'dias'}
        </span>
        <small>{stage.label}</small>
      </div>

      <span className="list-arrow">Abrir</span>
    </button>
  );
}

function DashboardManagement() {
  const navigate = useNavigate();
  const [complaints, setComplaints] = useState([]);
  const [filters, setFilters] = useState({
    status: '',
    type: '',
    search: ''
  });
  const [loading, setLoading] = useState(true);
  const [feedback, setFeedback] = useState('');

  useEffect(() => {
    const loadComplaints = async () => {
      setLoading(true);
      setFeedback('');

      try {
        const res = await api.get('/complaints');
        setComplaints(Array.isArray(res.data) ? res.data : []);
      } catch (error) {
        setFeedback('Nao foi possivel carregar as reclamacoes.');
      } finally {
        setLoading(false);
      }
    };

    loadComplaints();
  }, []);

  const filteredComplaints = useMemo(() => complaints.filter((item) => {
    const matchesStatus = !filters.status || item.status === filters.status;
    const matchesType = !filters.type || item.complaint_type === filters.type;
    const searchable = [
      item.protocol,
      item.patient_name,
      item.patient_phone,
      item.description,
      item.clinic_name,
      item.city,
      item.state,
      item.region
    ].map(normalizeText).join(' ');
    const matchesSearch = !filters.search || searchable.includes(normalizeText(filters.search));

    return matchesStatus && matchesType && matchesSearch;
  }), [complaints, filters]);

  const metrics = useMemo(() => {
    const total = complaints.length;
    const open = complaints.filter((item) => item.status === 'aberta').length;
    const inProgress = complaints.filter((item) => item.status === 'em_andamento').length;
    const resolved = complaints.filter((item) => item.status === 'resolvida').length;
    const resolvedRate = total ? Math.round((resolved / total) * 100) : 0;

    return { total, open, inProgress, resolved, resolvedRate };
  }, [complaints]);

  const byType = useMemo(() => groupCount(complaints, (item) => item.complaint_type), [complaints]);
  const byClinic = useMemo(() => groupCount(complaints, (item) => item.clinic_name).slice(0, 8), [complaints]);
  const byCity = useMemo(() => groupCount(complaints, (item) => item.city).slice(0, 8), [complaints]);
  const byState = useMemo(() => groupCount(complaints, (item) => item.state).slice(0, 8), [complaints]);
  const byRegion = useMemo(() => groupCount(complaints, (item) => item.region).slice(0, 8), [complaints]);

  return (
    <main className="app-page">
      <header className="page-heading">
        <div>
          <p className="eyebrow">Gestao de reclamacoes</p>
          <h1>Lista e controle de protocolos</h1>
          <p>Selecione uma reclamacao para abrir a pagina de gestao, registrar tratativa e fechar o protocolo.</p>
        </div>

        <div className="heading-actions">
          <button className="outline-action" onClick={() => navigate('/cadastro')}>
            Nova reclamacao
          </button>
          <button className="outline-action" onClick={() => navigate('/home')}>
            Home
          </button>
        </div>
      </header>

      <section className="kpi-grid" aria-label="Resumo operacional">
        <article className="kpi-card">
          <span>Total</span>
          <strong>{metrics.total}</strong>
          <p>reclamacoes registradas</p>
        </article>
        <article className="kpi-card warning">
          <span>Abertas</span>
          <strong>{metrics.open}</strong>
          <p>aguardando tratativa</p>
        </article>
        <article className="kpi-card progress">
          <span>Em andamento</span>
          <strong>{metrics.inProgress}</strong>
          <p>com acompanhamento</p>
        </article>
        <article className="kpi-card success">
          <span>Fechadas</span>
          <strong>{metrics.resolvedRate}%</strong>
          <p>{metrics.resolved} encerradas</p>
        </article>
      </section>

      <section className="chart-grid">
        <article className="chart-card large">
          <h2>Reclamacoes por tipo</h2>
          <div className="chart-box">
            <Doughnut data={buildDoughnutData(byType)} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por clinica</h2>
          <div className="chart-box">
            <Bar data={buildBarData(byClinic)} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por cidade</h2>
          <div className="chart-box">
            <Bar data={buildBarData(byCity)} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por estado</h2>
          <div className="chart-box">
            <Bar data={buildBarData(byState)} options={chartOptions} />
          </div>
        </article>

        <article className="chart-card">
          <h2>Volume por regiao</h2>
          <div className="chart-box">
            <Bar data={buildBarData(byRegion)} options={chartOptions} />
          </div>
        </article>
      </section>

      <section className="management-panel">
        <div className="panel-heading">
          <div>
            <p className="eyebrow">Protocolos</p>
            <h2>Lista de reclamacoes</h2>
          </div>

          <div className="filters">
            <input
              className="field"
              value={filters.search}
              onChange={(event) => setFilters({ ...filters, search: event.target.value })}
              placeholder="Buscar protocolo, paciente, clinica ou descricao"
            />
            <select
              className="field"
              value={filters.status}
              onChange={(event) => setFilters({ ...filters, status: event.target.value })}
            >
              <option value="">Todos os status</option>
              {statusOptions.map((status) => (
                <option key={status.value} value={status.value}>{status.label}</option>
              ))}
            </select>
            <select
              className="field"
              value={filters.type}
              onChange={(event) => setFilters({ ...filters, type: event.target.value })}
            >
              <option value="">Todos os tipos</option>
              {complaintTypes.map((type) => (
                <option key={type.value} value={type.label}>{type.label}</option>
              ))}
            </select>
          </div>
        </div>

        {feedback && <p className="form-feedback">{feedback}</p>}

        {loading ? (
          <p className="empty-state">Carregando reclamacoes...</p>
        ) : filteredComplaints.length === 0 ? (
          <p className="empty-state">Nenhuma reclamacao encontrada com os filtros atuais.</p>
        ) : (
          <div className="complaint-list management-list">
            {filteredComplaints.map((item) => (
              <ComplaintListItem
                item={item}
                key={item.id}
                onOpen={() => navigate(`/gestao/${item.id}`)}
              />
            ))}
          </div>
        )}
      </section>
    </main>
  );
}

export default DashboardManagement;
